package com.example.webhookhandler.service;

import com.example.webhookhandler.dto.WebhookResponse;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;
import org.springframework.web.client.RestTemplate;

import java.net.URI;

@Service
public class ContentFetchService {

    private final RestTemplate restTemplate;

    public ContentFetchService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    public WebhookResponse fetchContent(String url) {
        validateUrl(url);

        ResponseEntity<String> entity = restTemplate.getForEntity(URI.create(url), String.class);
        return WebhookResponse.success(url, entity.getStatusCodeValue(), entity.getBody());
    }

    private void validateUrl(String url) {
        if (!StringUtils.hasText(url)) {
            throw new IllegalArgumentException("URL is required");
        }

        URI uri;
        try {
            uri = URI.create(url);
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid URL");
        }

        String scheme = uri.getScheme();
        if (scheme == null || !(scheme.equalsIgnoreCase("http") || scheme.equalsIgnoreCase("https"))) {
            throw new IllegalArgumentException("Only http and https URLs are allowed");
        }

        if (uri.getHost() == null) {
            throw new IllegalArgumentException("URL host is required");
        }
    }
}

